('bookkeeper-moex-01372', 'bookkeeper', 'bookkeeper-moex-103-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依稅捐稽徵法第27條規定，納稅義務人對核准延期或分期繳納之任何一期應繳稅捐，未如期繳納者，稅捐 稽徵機關應於該期繳納期間屆滿之翌日起三日內，就未繳清之餘額稅款，發單通知納稅義務人，且限幾日 內一次全部繳清？', '["八日", "十日", "十五日", "二十日"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:27+00:00", "source_pdf_sha1": "bb46751672cc", "answer_pdf_sha1": "7502bd95d11d", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01373', 'bookkeeper', 'bookkeeper-moex-103-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依稅捐稽徵法第20條規定，逾期繳納稅捐應加徵滯納金者，每逾二日按滯納數額加徵百分之多少的滯納金？ 而逾幾日仍未繳納者，移送法院強制執行？', '["百分之一，30日", "百分之一，45日", "百分之二，30日", "百分之二，45日"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:27+00:00", "source_pdf_sha1": "bb46751672cc", "answer_pdf_sha1": "7502bd95d11d", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01374', 'bookkeeper', 'bookkeeper-moex-103-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依所得稅法第60條規定，一般情況下營利事業之著作權，應按幾年為計算攤折之標準？', '["五年", "十年", "十五年", "無規定"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:27+00:00", "source_pdf_sha1": "bb46751672cc", "answer_pdf_sha1": "7502bd95d11d", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01375', 'bookkeeper', 'bookkeeper-moex-103-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依所得稅法規定，綜合所得稅納稅義務人結算申報所列報之免稅及扣除項目或金額，超過規定之限制，致短 繳稅款，經稽徵機關核定補繳者，除補徵稅額外，亦應按日加計利息。而此一應加計之利息金額不超過多 少元者，免予加計徵收？', '["一千二百元", "一千五百元", "一千八百元", "二千元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:27+00:00", "source_pdf_sha1": "bb46751672cc", "answer_pdf_sha1": "7502bd95d11d", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01376', 'bookkeeper', 'bookkeeper-moex-103-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '王梅小姐102年度之綜合所得總額為350萬元，當年度捐贈給財團法人董氏基金會之捐款為30萬元，試問 102年度王小姐可以申報之捐贈列舉扣除額為多少元？', '["35萬元", "20萬元", "30萬元", "70萬元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:27+00:00", "source_pdf_sha1": "bb46751672cc", "answer_pdf_sha1": "7502bd95d11d", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01377', 'bookkeeper', 'bookkeeper-moex-103-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依所得稅法規定，自中華民國一百零一年一月一日起，符合規定條件之納稅義務人，得就五歲以下之子女， 每人每年扣除幼兒學前特別扣除額為多少元？', '["25,000元", "15,000元", "50,000元", "核實認列"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:27+00:00", "source_pdf_sha1": "bb46751672cc", "answer_pdf_sha1": "7502bd95d11d", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01378', 'bookkeeper', 'bookkeeper-moex-103-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '王午102年度就讀研究所在職專班支付學費45,000元，王午長子就讀某國立大學二年級學費50,000元， 王午長女就讀某私立五專四年級學費100,000元，則得列入王午102年度綜合所得稅申報之教育學費特別 扣除額為多少元？', '["25,000元", "150,000元", "50,000元", "195,000元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:27+00:00", "source_pdf_sha1": "bb46751672cc", "answer_pdf_sha1": "7502bd95d11d", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01379', 'bookkeeper', 'bookkeeper-moex-103-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '適用勞動基準法之營利事業，依勞動基準法提撥之勞工退休準備金，或依勞工退休金條例提繳之勞工退休金 或年金保險費，每年度得在不超過當年度已付薪資總額的多少限度內，以費用列支？', '["10%", "6%", "15%", "4%"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:27+00:00", "source_pdf_sha1": "bb46751672cc", "answer_pdf_sha1": "7502bd95d11d", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01380', 'bookkeeper', 'bookkeeper-moex-103-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '關於綜合所得稅列舉扣除之房屋租金支出，下列敘述何者正確？', '["範圍包括納稅義務人、配偶及受扶養親屬之房屋租金支出", "租屋地點不限中華民國境內或境外", "自住或供營業使用皆可", "申報有購屋借款利息者，不得扣除"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:27+00:00", "source_pdf_sha1": "bb46751672cc", "answer_pdf_sha1": "7502bd95d11d", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01381', 'bookkeeper', 'bookkeeper-moex-103-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依所得稅法規定，營利事業持有之短期票券發票日在中華民國九十九年一月一日以後者，其利息所得應如何 課稅？', '["無須課稅", "計入營利事業所得額課稅", "分離課稅，扣繳稅率為10%", "分離課稅，扣繳稅率為15%"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:27+00:00", "source_pdf_sha1": "bb46751672cc", "answer_pdf_sha1": "7502bd95d11d", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL)
